#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    for (int i = 0; i < T; i++) {
        int L, K;
        scanf("%d %d", &L, &K);
        int count = 0;
        for (int j = 0; j < L - K + 1; j++) {
            for (int k = 0; k < L - K + 1; k++) {
                if (j + K <= L && k + K <= L) {
                    count++;
                }
            }
        }
        printf("Case %d: %d\n", i + 1, count);
    }
    return 0;
}

