import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        for (int i = 0; i < T; i++) {
            int L = sc.nextInt();
            int K = sc.nextInt();
            int count = 0;
            for (int j = 0; j < L - K + 1; j++) {
                for (int k = 0; k < L - K + 1; k++) {
                    if (j + K <= L && k + K <= L) {
                        count++;
                    }
                }
            }
            System.out.println("Case " + (i + 1) + ": " + count);
        }
    }
}

